    "ims": {
      "rating": "red",
      "evidence": [
        "screener:derived.pcscf_sip_error_ratio is 1.0.",
        "metrics:pcscf:httpclient:connfail is high (285).",
        "metrics:pcscf:sl:200_replies is 0.",
        "ontology:subscriber_data_store_unavailable chain confirms mechanism."
